/**
 * Testo T549i BLE frame parser (DecoderMethod = Binary).
 *
 * With the Binary decoder, parse(frame) receives a 0-indexed Array of byte
 * values (0-255), one BLE notification per call. The probe prefixes each
 * IEEE-754 little-endian float with an ASCII field name; we scan for the name
 * and read the 4 bytes that follow it. Notifications without a marker (CRC
 * and status frames) just re-emit the held values, so every dataset updates
 * on a steady timeline.
 *
 * Output order matches dataset index 1,2: [pressure Pa, battery %]. The
 * Pressure dataset's Lua transform converts Pa to psi for display.
 */

var pressurePa  = 0;
var battery     = 0;

function indexOfMarker(frame, marker) {
  for (var i = 0; i + marker.length <= frame.length; ++i) {
    var hit = true;
    for (var j = 0; j < marker.length; ++j) {
      if (frame[i + j] !== marker.charCodeAt(j)) {
        hit = false;
        break;
      }
    }

    if (hit)
      return i + marker.length;
